import{_ as s,c as a,o as e,a as n}from"./app.87c00501.js";const l='{"title":"CSS","description":"","frontmatter":{},"headers":[{"level":2,"title":"CSS Properties","slug":"css-properties"},{"level":2,"title":"CSS Variable","slug":"css-variable"},{"level":3,"title":"Syntax","slug":"syntax"},{"level":3,"title":"Scopes in CSS Variable","slug":"scopes-in-css-variable"}],"relativePath":"docs/css/CSS2.md"}',r={},p=[n('<h1 id="css" tabindex="-1">CSS <a class="header-anchor" href="#css" aria-hidden="true">#</a></h1><h2 id="css-properties" tabindex="-1">CSS Properties <a class="header-anchor" href="#css-properties" aria-hidden="true">#</a></h2><p>::before 选择器向选定的<strong>元素</strong>前插入内容</p><p>hsl() 函数使用色相、饱和度、亮度来定义颜色。</p><p>HSL 即色相、饱和度、亮度（英语：Hue, Saturation, Lightness）。</p><ul><li>**色相（H）**是色彩的基本属性，就是平常所说的颜色名称，如红色、黄色等。</li><li>**饱和度（S）**是指色彩的纯度，越高色彩越纯，低则逐渐变灰，取 0-100% 的数值。</li><li><strong>亮度（L）</strong>，取 0-100%，增加亮度，颜色会向白色变化；减少亮度，颜色会向黑色变化。</li></ul><p>HSL 是一种将 RGB 色彩模型中的点在圆柱坐标系中的表示法。这两种表示法试图做到比基于笛卡尔坐标系的几何结构 RGB 更加直观。</p><p>CSS overflow 属性可以控制内容溢出元素框时在对应的元素区间内添加滚动条</p><p><img src="/assets/image-20220511194221503.11e0164f.png" alt=""></p><h2 id="css-variable" tabindex="-1">CSS Variable <a class="header-anchor" href="#css-variable" aria-hidden="true">#</a></h2><h3 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-hidden="true">#</a></h3><h4 id="declaring-a-css-variable" tabindex="-1">Declaring a CSS variable <a class="header-anchor" href="#declaring-a-css-variable" aria-hidden="true">#</a></h4><div class="language-css"><pre><code><span class="line"><span style="color:#A6ACCD;">--variable-name: </span><span style="color:#FFCB6B;">some-value</span><span style="color:#A6ACCD;">;</span></span>\n<span class="line"></span></code></pre></div><h4 id="using-the-css-variable" tabindex="-1">Using the CSS variable <a class="header-anchor" href="#using-the-css-variable" aria-hidden="true">#</a></h4><div class="language-css"><pre><code><span class="line"><span style="color:#FFCB6B;">css-property</span><span style="color:#A6ACCD;">: var(--variable-name);</span></span>\n<span class="line"></span></code></pre></div><h3 id="scopes-in-css-variable" tabindex="-1">Scopes in CSS Variable <a class="header-anchor" href="#scopes-in-css-variable" aria-hidden="true">#</a></h3><h4 id="global-scope" tabindex="-1">Global Scope <a class="header-anchor" href="#global-scope" aria-hidden="true">#</a></h4><div class="language-css"><pre><code><span class="line"><span style="color:#89DDFF;">:</span><span style="color:#C792EA;">root</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">  --primary-color</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">#</span><span style="color:#A6ACCD;">000</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#FFCB6B;">h1</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#B2CCD6;">color</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">var</span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">--primary-color</span><span style="color:#89DDFF;">);</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span></span>\n<span class="line"></span></code></pre></div>',18)];var o=s(r,[["render",function(s,n,l,r,o,i){return e(),a("div",null,p)}]]);export{l as __pageData,o as default};
